use actix_web::{web, App, HttpServer, HttpResponse, Result, http::header};
use std::path::{Path, PathBuf};
use std::fs;

const UPLOADS_DIR: &str = "./uploads";

async fn serve_file(path: web::Path<String>) -> Result<HttpResponse> {
    let filename = path.into_inner();
    
    // Resolve the filename against the uploads directory
    let base_path = Path::new(UPLOADS_DIR);
    let resolved_path = base_path.join(&filename);
    
    // Canonicalize the path to resolve any symbolic links or relative paths
    let canonical_path = resolved_path.canonicalize()
        .map_err(|_| actix_web::error::ErrorNotFound("File not found"))?;
    
    // Ensure the resolved path is within the uploads directory
    if !canonical_path.starts_with(base_path) {
        return Err(actix_web::error::ErrorForbidden("Access denied"));
    }
    
    // Check if the file exists and is a regular file
    if !canonical_path.is_file() {
        return Err(actix_web::error::ErrorNotFound("File not found"));
    }
    
    // Read the file contents
    let content = fs::read(&canonical_path)
        .map_err(|_| actix_web::error::ErrorInternalServerError("Failed to read file"))?;
    
    // Determine content type based on file extension
    let content_type = match canonical_path.extension().and_then(|ext| ext.to_str()) {
        Some("txt") => "text/plain",
        Some("html") => "text/html",
        Some("css") => "text/css",
        Some("js") => "application/javascript",
        Some("json") => "application/json",
        Some("xml") => "application/xml",
        Some("png") => "image/png",
        Some("jpg") | Some("jpeg") => "image/jpeg",
        Some("gif") => "image/gif",
        Some("svg") => "image/svg+xml",
        Some("pdf") => "application/pdf",
        Some("zip") => "application/zip",
        Some("mp4") => "video/mp4",
        Some("mp3") => "audio/mpeg",
        _ => "application/octet-stream",
    };
    
    Ok(HttpResponse::Ok()
        .content_type(content_type)
        .body(content))
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}